        endcase
    end

    // W-ready MUX (FIFO-tracked w_slave_select — awaddr has already reverted by W phase)
    always_comb begin
        fub_axi_wready = 1'b0;
        case (w_slave_select)
            2'b01: begin  // Slave 0 (32b)
                fub_axi_wready = dma_32b_wready;
            end
            2'b10: begin  // Slave 1 (32b)
                fub_axi_wready = dma_32b_wready;
            end
            default: begin
                // No active W transaction
            end
        endcase
    end

    // Write response MUX (B channel - uses b_slave_select FIFO head)
    always_comb begin
        fub_axi_bid = 4'd0;
        fub_axi_bresp = 2'b00;
        fub_axi_bvalid = 1'b0;

        case (b_slave_select)
            2'b01: begin  // Slave 0 (32b)
                fub_axi_bid = dma_32b_b.id;
                fub_axi_bresp = dma_32b_b.resp;
                fub_axi_bvalid = dma_32b_bvalid;
            end
            2'b10: begin  // Slave 1 (32b)
                fub_axi_bid = dma_32b_b.id;
                fub_axi_bresp = dma_32b_b.resp;
                fub_axi_bvalid = dma_32b_bvalid;
            end
            default: begin
                // No slave selected - hold defaults
            end
        endcase
    end

    // AR-ready MUX (request side: uses combinational comb_slave_select_ar)
    always_comb begin
        fub_axi_arready = 1'b0;
        case (comb_slave_select_ar)
            2'b01: begin  // Slave 0 (32b)
                fub_axi_arready = dma_32b_arready;
            end
            2'b10: begin  // Slave 1 (32b)
                fub_axi_arready = dma_32b_arready;
            end
            default: begin
                // No slave selected
            end
        endcase
    end

    // Read response MUX (R channel - uses r_slave_select FIFO head)
    always_comb begin
        fub_axi_rid = 4'd0;
        fub_axi_rdata = 32'd0;
        fub_axi_rresp = 2'b00;
        fub_axi_rlast = 1'b0;
        fub_axi_rvalid = 1'b0;

        case (r_slave_select)
            2'b01: begin  // Slave 0 (32b)
                fub_axi_rid = dma_32b_r.id;
                fub_axi_rdata = dma_32b_r.data;
                fub_axi_rresp = dma_32b_r.resp;
                fub_axi_rlast = dma_32b_r.last;
                fub_axi_rvalid = dma_32b_rvalid;
            end
            2'b10: begin  // Slave 1 (32b)
                fub_axi_rid = dma_32b_r.id;
                fub_axi_rdata = dma_32b_r.data;
                fub_axi_rresp = dma_32b_r.resp;
                fub_axi_rlast = dma_32b_r.last;
                fub_axi_rvalid = dma_32b_rvalid;
            end
            default: begin
                // No slave selected - hold defaults
            end
        endcase
    end

endmodule : dma_adapter
